\begin{align*}
\angle ABC_1 + \angle ABC_2 &= (140^\circ - \angle AC_1 B) + (140^\circ - \angle AC_2 B) \\
&= 280^\circ - (\angle AC_1 B + \angle AC_2 B) \\
