  return (sin(t/4),cos(t/4));
}

real t;
path foo = moo(0);

for (t = 0; t <= 8*pi; t = t + 0.01) {
  foo = foo--moo(t);
}

draw((-1.2,0)--(1.2,0));
draw((0,-1.2)--(0,1.2));
